    PreCategoryOfStructures.f
      {|
        morphism_isomorphic := 1;
        isisomorphism_isomorphic := isisomorphism_identity StrX xa
      |};
  isisomorphism_isomorphic :=
    {|
      morphism_inverse :=
        PreCategoryOfStructures.f
          {|
            morphism_isomorphic := 1;
            isisomorphism_isomorphic := isisomorphism_identity StrX xa
          |}^-1;
      left_inverse := ap (PreCategoryOfStructures.f (yb:=xa)) left_inverse;
      right_inverse := ap (PreCategoryOfStructures.f (yb:=xa)) right_inverse
    |}
|} =
{|
  morphism_isomorphic := 1;
  isisomorphism_isomorphic := isisomorphism_identity X xa.1
|}

